    }

    if (this.wsServer) {
      this.wsServer.close();
    }

    if (this.broker) {
      await new Promise(resolve => this.broker.close(resolve));
    }

    this.logger.info('✅ MQTT Handler shutdown complete');
  }

  writeData() { 
    this.logger.info('� MQTT broker ready for publishes'); 
  }

  close() { 
