import { GatewayConfig } from '../gatewayGenerator';

export function generateMqttHandler(config: GatewayConfig): string {
  return `const mqtt = require('mqtt');
const Aedes = require('aedes');
const net = require('net');
const ws = require('ws');

class MqttHandler {
  constructor(protocolConfig, logger) {
    this.config = protocolConfig;
    this.logger = logger;
    this.topics = new Map();
    this.broker = null;
    this.server = null;
    this.wsServer = null;
    this.clients = new Set();
    this.initialize();
  }

  async initialize() {
    if (!this.config.enabled) {
      this.logger.info('🚫 MQTT protocol is disabled');
      return true;
    }

    try {
      this.logger.info('🚀 Initializing MQTT Broker...');
      
      // Setup topics first
      this.setupTopics();
      
      if (this.config.mode === 'server') {
        await this.startMqttBroker();
      }

      this.logger.info('✅ MQTT protocol handler initialized successfully');
      return true;

    } catch (error) {
      this.logger.error('❌ Failed to initialize MQTT protocol handler:', error);
      return false;
    }
  }

  async startMqttBroker() {
    const brokerPort = this.config.settings?.brokerPort || 1883;
    const wsPort = this.config.settings?.wsPort || 8883;
    
    this.logger.info(\`🔧 Starting MQTT Broker on port \${brokerPort}...\`);
    this.logger.info(\`🌐 WebSocket MQTT on port \${wsPort}...\`);

    // Create Aedes broker instance
    this.broker = new Aedes({
      id: 'gateway-mqtt-broker',
      heartbeatInterval: 60000,
      connectTimeout: 30000
    });

    // Set up broker event handlers
    this.setupBrokerEvents();

    // Create TCP server for MQTT
    this.server = net.createServer(this.broker.handle);
    
    // Create WebSocket server for MQTT over WebSocket
    this.wsServer = new ws.Server({ port: wsPort });
    this.wsServer.on('connection', (ws) => {
      const stream = ws.createStream();
      this.broker.handle(stream);
    });

    // Start the TCP server
    return new Promise((resolve, reject) => {
      this.server.listen(brokerPort, (err) => {
        if (err) {
          this.logger.error(\`❌ Failed to start MQTT broker: \${err.message}\`);
          reject(err);
        } else {
          this.logger.info(\`✅ MQTT Broker started on port \${brokerPort}\`);
          this.logger.info(\`✅ MQTT WebSocket started on port \${wsPort}\`);
          this.logger.info(\`🌍 Clients can connect to mqtt://localhost:\${brokerPort}\`);
          this.logger.info(\`🌍 WebSocket clients can connect to ws://localhost:\${wsPort}\`);
          resolve();
        }
      });
    });
  }

  setupBrokerEvents() {
    this.broker.on('client', (client) => {
      this.clients.add(client.id);
      this.logger.info(\`🔗 MQTT client connected: \${client.id}\`);
    });

    this.broker.on('clientDisconnect', (client) => {
      this.clients.delete(client.id);
      this.logger.info(\`🔌 MQTT client disconnected: \${client.id}\`);
    });

    this.broker.on('subscribe', (subscriptions, client) => {
      subscriptions.forEach(sub => {
        this.logger.info(\`📡 Client \${client.id} subscribed to: \${sub.topic}\`);
      });
    });

    this.broker.on('unsubscribe', (unsubscriptions, client) => {
      unsubscriptions.forEach(topic => {
        this.logger.info(\`📡 Client \${client.id} unsubscribed from: \${topic}\`);
      });
    });

    this.broker.on('publish', (packet, client) => {
      const clientId = client ? client.id : 'server';
      this.logger.info(\`📤 MQTT publish from \${clientId}: \${packet.topic} = \${packet.payload}\`);
      
      // Update local topic storage
      if (this.topics.has(packet.topic)) {
        const topic = this.topics.get(packet.topic);
        let value = packet.payload.toString();
        
        // Convert based on data type
        switch (topic.dataType) {
          case 'boolean':
            value = value.toLowerCase() === 'true';
            break;
          case 'double':
            value = parseFloat(value);
            break;
        }
        
        this.topics.set(packet.topic, {
          ...topic,
          value: value,
          quality: 'good',
          timestamp: new Date().toISOString()
        });
      }
    });
  }

  setupTopics() {
    // Initialize configured topics or use defaults
    const configuredTopics = this.config.settings?.topics || [];
    
    if (configuredTopics.length > 0) {
      configuredTopics.forEach(topicConfig => {
        this.topics.set(topicConfig.topic, {
          topic: topicConfig.topic,
          dataType: topicConfig.dataType || 'string',
          value: topicConfig.defaultValue || null,
          quality: 'good',
          timestamp: new Date().toISOString(),
          writable: topicConfig.writable !== false
        });
      });
    } else {
      // Default sample topics if none configured
      const sampleTopics = [
        { topic: 'sensor/temperature', dataType: 'double', value: 22.5, writable: true },
        { topic: 'sensor/humidity', dataType: 'double', value: 65.0, writable: false },
        { topic: 'device/status', dataType: 'string', value: 'online', writable: true },
        { topic: 'alarm/critical', dataType: 'boolean', value: false, writable: true },
        { topic: 'control/setpoint', dataType: 'double', value: 25.0, writable: true }
      ];

      sampleTopics.forEach(topicData => {
        this.topics.set(topicData.topic, {
          topic: topicData.topic,
          dataType: topicData.dataType,
          value: topicData.value,
          quality: 'good',
          timestamp: new Date().toISOString(),
          writable: topicData.writable
        });
      });
    }
    
    this.logger.info(\`📊 Initialized \${this.topics.size} MQTT topics\`);
  }

  getVariableList() {
    return Array.from(this.topics.entries()).map(([name, config]) => ({
      name,
      topic: config.topic,
      dataType: config.dataType,
      readable: true,
      writable: config.writable
    }));
  }

  readVariable(variableName, deviceName) {
    try {
      if (!this.topics.has(variableName)) {
        throw new Error(\`MQTT topic '\${variableName}' not found\`);
      }

      const topic = this.topics.get(variableName);
      this.logger.info(\`📖 Reading MQTT topic: \${variableName}\`);

      return {
        value: topic.value,
        dataType: topic.dataType,
        quality: topic.quality,
        timestamp: topic.timestamp,
        topic: topic.topic
      };
    } catch (error) {
      this.logger.error(\`MQTT read error for \${variableName}:\`, error);
      return {
        value: null,
        dataType: 'unknown',
        quality: 'bad',
        timestamp: new Date().toISOString(),
        error: error.message
      };
    }
  }

  writeVariable(variableName, value, deviceName) {
    try {
      if (!this.topics.has(variableName)) {
        throw new Error(\`MQTT topic '\${variableName}' not found\`);
      }

      const topic = this.topics.get(variableName);
      
      if (!topic.writable) {
        throw new Error(\`MQTT topic '\${variableName}' is not writable\`);
      }

      // Validate and convert value based on data type
      let validatedValue = value;
      switch (topic.dataType) {
        case 'boolean':
          validatedValue = Boolean(value);
          break;
        case 'double':
          validatedValue = parseFloat(value);
          if (isNaN(validatedValue)) {
            throw new Error(\`Invalid double value: \${value}\`);
          }
          break;
        case 'string':
          validatedValue = String(value);
          break;
        default:
          validatedValue = value;
      }

      const previousValue = topic.value;
      
      // Update local topic storage
      this.topics.set(variableName, {
        ...topic,
        value: validatedValue,
        quality: 'good',
        timestamp: new Date().toISOString()
      });

      // Publish to MQTT broker if running
      if (this.broker) {
        const packet = {
          topic: variableName,
          payload: Buffer.from(String(validatedValue)),
          qos: 0,
          retain: true
        };
        
        this.broker.publish(packet, () => {
          this.logger.info(\`📤 MQTT published: \${variableName} = \${validatedValue}\`);
        });
      }

      return {
        success: true,
        message: \`Successfully published \${validatedValue} to MQTT topic \${variableName}\`,
        previousValue: previousValue
      };
    } catch (error) {
      this.logger.error(\`MQTT write error for \${variableName}:\`, error);
      return {
        success: false,
        message: error.message
      };
    }
  }

  getData(deviceName) {
    const variables = {};
    this.topics.forEach((data, name) => {
      variables[name] = data.value;
    });
    
    return { 
      message: 'MQTT Broker ready',
      connected: true,
      variables,
      topicCount: this.topics.size,
      clientCount: this.clients.size,
      timestamp: new Date().toISOString()
    };
  }

  async shutdown() {
    this.logger.info('� Shutting down MQTT Handler...');
    
    if (this.server) {
      this.server.close();
    }
    
    if (this.wsServer) {
      this.wsServer.close();
    }
    
    if (this.broker) {
      await new Promise(resolve => this.broker.close(resolve));
    }
    
    this.logger.info('✅ MQTT Handler shutdown complete');
  }

  writeData() { 
    this.logger.info('� MQTT broker ready for publishes'); 
  }

  close() { 
    this.shutdown();
  }
}

module.exports = MqttHandler;
`;
}
